B.NW=new A.Q(B.a7,"Modals express obligation and permission",'Modal verbs are essential in aviation English because they express **degrees of obligation**. The difference between "must" and "should" can have safety implications.\n\n**must** = mandatory (regulatory requirement)\n**should** = recommended (best practice)\n**may** = permitted (allowed)\n**can** = ability / theoretical possibility',null,null,null)
B.PV=new A.Q(B.eN,"Modal strength spectrum",null,null,B.qj,null)
B.NO=new A.Q(B.B,"Modal + Verb Structure",'**Rule:** Modal verb + **base infinitive** (no "to", no "-s", no "-ing")\n\n\u2713 The pilot **must check** the fuel level.\n\u2717 The pilot must **checks** / must **checking** / must **to check**\n\n**With passive:**\nModal + **be** + past participle\n\u2713 The engine **must be shut down** before maintenance.\n\u2713 Parts **should be inspected** visually.',null,null,null)
B.Jb=new A.aA("The engine must be shut down before any maintenance work begins.","Herhangi bir bak\u0131m \xe7al\u0131\u015fmas\u0131 ba\u015flamadan \xf6nce motor kapat\u0131lmal\u0131d\u0131r.","must be shut down")
B.Ki=new A.aA("Technicians should wear protective equipment when handling fuel.","Teknisyenler yak\u0131t ile \xe7al\u0131\u015f\u0131rken koruyucu ekipman takmal\u0131d\u0131r.","should wear")
B.JK=new A.aA("The aircraft may depart after all checks are completed.","T\xfcm kontroller tamamland\u0131ktan sonra u\xe7ak kalkabilir.","may depart")
B.JH=new A.aA("Contaminated parts must not be reinstalled without inspection.","Kirlenmi\u015f par\xe7alar incelenmeden yeniden tak\u0131lmamal\u0131d\u0131r.","must not be reinstalled")
B.SZ=s([B.Jb,B.Ki,B.JK,B.JH],t.l)
B.OQ=new A.Q(B.a8,"Modals in Context",null,B.SZ,null,null)
B.NI=new A.Q(B.a9,"\u2708\ufe0f Exam Tip",'Common distractors in modal questions:\n\u2022 "must checking" \u2192 WRONG (modal + base form, not -ing)\n\u2022 "should to inspect" \u2192 WRONG (no "to" after modals)\n\u2022 "must performed" \u2192 WRONG (passive needs "be": must **be** performed)\n\nIf you see a modal verb + gap, check: is an active or passive meaning needed?',null,null,null)
