B.Ou=new A.Q(B.a7,"Articles signal definiteness and context",'While articles seem simple, they are among the most frequently tested grammar points in aviation English because technical documents, manuals, and ATC communications all follow specific article usage patterns.\n\nA wrong article changes the meaning: "**a** hydraulic pump" (any one) vs. "**the** hydraulic pump" (a specific one we are discussing).',null,null,null)
B.KC=new A.nV(5,"articleUsage")
B.Q7=new A.Q(B.eN,"Article usage guide",null,null,B.KC,null)
B.Od=new A.Q(B.B,"Article Rules",'**"a / an"** \u2014 indefinite: first mention, one of many, job/type\n\u2192 "A hydraulic pump pressurizes the fluid."\n\u2192 "He is a licensed aircraft engineer."\n\n**"the"** \u2014 definite: previously mentioned, unique, specific system\n\u2192 "The hydraulic pump (mentioned before) failed."\n\u2192 "The captain (there is only one) made the decision."\n\n**Zero article** \u2014 general statements, uncountable nouns, proper names\n\u2192 "Aviation safety depends on training." (general)\n\u2192 "ILS runway 36L is available." (proper name)',null,null,null)
B.JV=new A.aA("The aircraft is equipped with a hydraulic system that powers the flight controls.","U\xe7ak, u\xe7u\u015f kontrollerini g\xfc\xe7lendiren bir hidrolik sistemle donat\u0131lm\u0131\u015ft\u0131r.","a hydraulic system")
B.K0=new A.aA("An ELT must be installed on all aircraft operating under IFR.","IFR alt\u0131nda u\xe7u\u015f yapan t\xfcm u\xe7aklarda bir ELT bulunmal\u0131d\u0131r.","An ELT")
B.K7=new A.aA("Aviation fuel must be free of contaminants before being loaded.","Havac\u0131l\u0131k yak\u0131t\u0131 y\xfcklenmeden \xf6nce kirleticilerden ar\u0131nd\u0131r\u0131lm\u0131\u015f olmal\u0131d\u0131r.","Aviation fuel")
